// Extract message data
const msg = $input.first().json;
const text = msg.message?.text || '';
const chatId = msg.message?.chat?.id || 0;
const allowedChatId = parseInt($env.TG_CHAT_ID || '0');

// Authorization check
if (chatId !== allowedChatId) {
  return [{ json: { reply: '⛔ No autorizado.', chatId: chatId } }];
}

// Route command to the bibliotecario handler
const { execSync } = require('child_process');
try {
  const cmd = `cd /home/lucy-ubuntu/Escritorio/NIN && /home/lucy-ubuntu/Escritorio/NIN/.venv/bin/python3 -c "
import sys, json
sys.path.insert(0, 'scripts')
from bibliotecario.telegram_handler import handle_command
result = handle_command(json.loads(sys.argv[1]), ${chatId})
print(json.dumps({'reply': result}))
" '${JSON.stringify(text).replace(/'/g, "'\\''")}'`;
  const result = JSON.parse(execSync(cmd, { timeout: 30000 }).toString());
  return [{ json: { reply: result.reply, chatId: chatId } }];
} catch(e) {
  return [{ json: { reply: '❌ Error procesando comando: ' + e.message, chatId: chatId } }];
}
